  public String generatePassword(SailPointContext context){
    PasswordGenerator generator = new PasswordGenerator(context);
    PasswordPolicy policy = context.getObject(PasswordPolicy.class, "GSuite Strong PasswordPolicy");
    String newPassword = generator.generatePassword(policy);
    return newPassword;
  }

  public ProvisioningPlan buildGSuiteLeaverPlan(SailPointContext context, String identityName, ProvisioningPlan plan){
    if(plan == null) plan = new ProvisioningPlan();
    Identity identity = context.getObjectByName(Identity.class,identityName);

    boolean isLeagalHold = isLegalHold(identity);

    //Name of the GSuite application hardcoded here
    String appName ="GSuite";

    Application appObj = context.getObjectByName(Application.class, appName);

    IdentityService idService = new IdentityService(context);
    List links = idService.getLinks(identity, appObj);

    if(links != null && !links.isEmpty()){
      for(Link appLink:links){
        AccountRequest accReq = getModifyAccountRequest(appName, appLink.getNativeIdentity());
        if(!isLeagalHold){
          //Add manager as delegated admin
          String managerEmail = getManagerGsuiteEmail(context, identity);
          if(managerEmail != null){
            transferData(context,identity);
            delegateCalendar(context,identity);

            //Delegation works only for mailbox. This is limitation from the GSuite API https://developers.google.com/gmail/api/v1/reference/users/settings/delegates
            //accReq.add(addDelgateAdmin(managerEmail));
          }
        }

        //Set changePasswordAtNextLogin to true
        changePasswordAtNextLogin(context,appObj,appLink.getNativeIdentity(),true);

        //Change users password to invalidate current sessions
        accReq.add(changePassword(generatePassword(context)));
        
        //Remove the users account from the Global Address List
        accReq.add(includeInGlobalAddressList("false"));        

        //remove all entitlements -- Not used at this time
        //List removeAttrs = removeAllEntitlements(identity, appName, appLink);
        //if(removeAttrs != null && !removeAttrs.isEmpty())     accReq.addAll(removeAttrs);

        plan.add(accReq);
      }
    }
    return plan;
  }
